def _week_monday(iso: str) -> date:
    d = date.fromisoformat(iso)
    return d - timedelta(days=d.weekday())


def _days_in_week(monday: date):
    return [(monday + timedelta(days=i), WEEKDAYS[i]) for i in range(5)]


def _task_status(child: str, day_iso: str, subject: str, task_text: str):
    """Return 'done'|'missed'|'upcoming' based on task registry."""
    from data_helpers import load_task_registry
    registry = load_task_registry()
    full_key = f"SCHOOL::{subject}::{task_text}"

    entries = registry.get(child, {}).get(day_iso, [])
    if full_key in entries:
        return "done"

    today = date.today().isoformat()
    if day_iso < today:
        return "missed"

    return "upcoming"


